mapper.select:
SELECT

FROM record.trip_record_entries e
JOIN trip.trips t ON t.id = e.trip_id
WHERE e.trip_id = #{tripId}
  AND e.status = 'ACTIVE'
ORDER BY e.taken_at DESC NULLS LAST, e.created_at DESC, e.id DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT

FROM record.trip_record_entries e
JOIN trip.trips t ON t.id = e.trip_id
WHERE e.trip_id = #{tripId}
  AND e.id = #{recordId}
  AND e.status = 'ACTIVE'

WITH requested_trips AS ( SELECT t.id FROM trip.trips t WHERE t.id IN
#{tripId}
AND t.status != 'DELETED' AND ( t.owner_user_id = #{userId} OR EXISTS ( SELECT 1 FROM trip.trip_members tm WHERE tm.trip_id = t.id AND tm.user_id = #{userId} AND tm.status = 'ACTIVE' ) ) ), photo_summaries AS ( SELECT e.trip_id, count(*) AS photo_count, (array_agg( m.id ORDER BY e.taken_at DESC NULLS LAST, e.created_at DESC, e.id DESC, rm.sort_order ASC, m.id ASC ))[1] AS cover_media_file_id, (array_agg( m.object_key ORDER BY e.taken_at DESC NULLS LAST, e.created_at DESC, e.id DESC, rm.sort_order ASC, m.id ASC ))[1] AS cover_object_key, (array_agg( m.public_url ORDER BY e.taken_at DESC NULLS LAST, e.created_at DESC, e.id DESC, rm.sort_order ASC, m.id ASC ))[1] AS cover_url FROM record.trip_record_entries e JOIN requested_trips rt ON rt.id = e.trip_id JOIN record.trip_record_media rm ON rm.record_entry_id = e.id JOIN media.media_files m ON m.id = rm.media_file_id WHERE e.status = 'ACTIVE' AND m.status = 'ACTIVE' AND m.mime_type LIKE 'image/%' GROUP BY e.trip_id ) SELECT rt.id AS trip_id, COALESCE(ps.photo_count, 0) AS photo_count, ps.cover_media_file_id, ps.cover_object_key, ps.cover_url AS cover_public_url FROM requested_trips rt LEFT JOIN photo_summaries ps ON ps.trip_id = rt.id ORDER BY rt.id
